const dist = $input.first().json[0];

if (!dist) {
  throw new Error('Distributor not found');
}

const sponsorName = dist.sponsor 
  ? `${dist.sponsor.first_name} ${dist.sponsor.last_name}`
  : 'Direct';

return [{
  json: {
    distributorId: dist.id,
    firstName: dist.first_name,
    lastName: dist.last_name,
    fullName: `${dist.first_name} ${dist.last_name}`,
    email: dist.email,
    phone: dist.phone,
    slug: dist.slug,
    city: dist.city,
    state: dist.state,
    licensingStatus: dist.licensing_status,
    sponsorName: sponsorName,
    sponsorSlug: dist.sponsor ? dist.sponsor.slug : null,
    registrationType: dist.registration_type,
    createdAt: dist.created_at
  }
}];

const dist = $input.first().json;

const messages = {
  facebook: `🎉 Welcome ${dist.fullName} from ${dist.city}, ${dist.state}!

They just joined the Apex Affinity Group family as a ${dist.licensingStatus === 'licensed' ? 'licensed agent' : 'distributor'}.

Let's show them some love! 💙

#ApexFamily #NetworkMarketing #Welcome`,

  twitter: `🌟 Big news! ${dist.fullName} from ${dist.state} is now part of the Apex movement!

Welcome to the family! 🚀

#ApexFamily #NewMember`,

  linkedin: `We're excited to welcome ${dist.fullName} from ${dist.city}, ${dist.state} to the Apex Affinity Group!

${dist.licensingStatus === 'licensed' ? 'As a licensed insurance professional' : 'As a new distributor'}, they're ready to make an impact.

Welcome aboard! 👏

#ApexAffinity #TeamGrowth`
};

return [{
  json: {
    ...dist,
    socialMessages: messages
  }
}];

